            // Warm-up scramble to avoid initial correlation
            for (int i = 0; i < 10; i++)
            {
                uint x = _state;
                x ^= x << 13;
                x ^= x >> 17;
                x ^= x << 5;
                _state = x;
            }
        }

        public uint Next()
        {
            uint x = _state;
            x ^= x << 13;
            x ^= x >> 17;
            x ^= x << 5;
            _state = x;
            return x;
        }

        /// <summary>Returns a double in [0, 1)</summary>
        public double NextDouble()
        {
            return Next() / (double)uint.MaxValue;
        }
    }

