                // Compute layer vertical bounds for stacking
                double minY = double.MaxValue;
                double maxY = double.MinValue;
                for (int si = 0; si < rawSpheres.Count; si++)
                {
                    double bottom = rawSpheres[si].Y - rawSpheres[si].Radius;
                    double top = rawSpheres[si].Y + rawSpheres[si].Radius;
