                    s.CutByCondensation = hasCondensation && (s.Y - s.Radius < layer.CondensationLevel);
                }

                cumulativeY = yOffset + maxY + gap;
                allSpheres.AddRange(rawSpheres);
            }

            allSpheres.RemoveAll(s => s.CutByCondensation);
            return allSpheres;
        }

