                double jitX = CloudMath.Perlin3D(pt.x * 15, pt.y * 15, pt.z * 15, seed) * jitterStrength;
                double jitY = CloudMath.Perlin3D(pt.x * 15, pt.y * 15, pt.z * 15, seed + 1) * jitterStrength;
                double jitZ = CloudMath.Perlin3D(pt.x * 15, pt.y * 15, pt.z * 15, seed + 2) * jitterStrength;
                double jptX = pt.x + jitX * frame.Radius;
