        private static List<CloudSphere> GenerateColumnLayer(CloudLayerConfig layer, ref DeterministicRandom rng)
        {
            var spheres = new List<CloudSphere>();

            int seed = layer.Seed;
            double jitter = layer.Jitter;
            double clustering = layer.Clustering;
            double posVariation = layer.PositionVariation;
            int sizeMin = layer.SizeRange.Min;
            int sizeMax = layer.SizeRange.Max;

            double height = layer.ColumnParams.Height;
            double baseRadius = layer.ColumnParams.BaseRadius;
            double topRadius = layer.ColumnParams.TopRadius;
            int floors = layer.ColumnParams.Floors;
            int ringsPerFloor = layer.ColumnParams.RingsPerFloor;
            double wobble = layer.ColumnParams.Wobble / 100.0;

            double floorSpacing = height / floors;

            for (int floor = 0; floor < floors; floor++)
            {
                double t = floor / (double)(floors - 1 <= 0 ? 1 : floors - 1);
                double floorRadius = baseRadius + (topRadius - baseRadius) * t;

                double y = floor * floorSpacing;

                double wobbleX = CloudMath.Perlin3D(floor * 0.7, 0, 0, seed)
                                 * wobble * floorRadius
                                 + jitter * baseRadius * 2.0
                                   * CloudMath.Perlin3D(floor, 0, 0, seed + 1);
                double wobbleZ = CloudMath.Perlin3D(floor * 0.7, 0, 0, seed + 100)
                                 * wobble * floorRadius
                                 + jitter * baseRadius * 2.0
                                   * CloudMath.Perlin3D(floor, 0, 0, seed + 2);

                for (int r = 0; r < ringsPerFloor; r++)
                {
                    double angle = (r / (double)ringsPerFloor) * Math.PI * 2
                                   + CloudMath.Perlin3D(floor * 0.3, r * 0.5, seed, seed)
                                     * 0.5 * (1.0 + jitter * 2.0);
                    double distNoise = CloudMath.Perlin3D(floor * 0.5, r * 0.7, seed + 50, seed);
                    double distFromCenter = floorRadius
                                            * (0.3 + (distNoise + 1.0) * 0.5 * 0.7 + 0.5)
                                            * 0.5;
                    double jitR = CloudMath.Perlin3D(floor, r, seed, seed) * jitter * 0.5;

                    double rNoiseBase = Math.Pow(
                        (CloudMath.Perlin3D(floor + r * 0.1, r + floor * 0.1, seed + 200, seed)
                         + 1.0) * 0.5, 1.8);
                    double rNoiseMult = Math.Pow(
                        (CloudMath.Perlin3D(floor + r * 0.1 + 50, r + floor * 0.1 + 50, seed + 250, seed)
                         + 1.0) * 0.5, 1.5);
                    double sizeBase = sizeMin + rNoiseBase * (sizeMax - sizeMin);
                    double sphereRadius = baseRadius * sizeBase * 0.12 * (0.1 + rNoiseMult * 0.9);

                    double colOx = (rng.NextDouble() - 0.5) * 12.0 * sphereRadius * posVariation;
                    double colOy = (rng.NextDouble() - 0.5) * 12.0 * sphereRadius * posVariation;
                    double colOz = (rng.NextDouble() - 0.5) * 12.0 * sphereRadius * posVariation;

                    spheres.Add(new CloudSphere
                    {
                        X = (float)(Math.Cos(angle) * distFromCenter + wobbleX + colOx),
                        Y = (float)(y + jitR * 0.3 + colOy),
                        Z = (float)(Math.Sin(angle) * distFromCenter + wobbleZ + colOz),
                        Radius = (float)Math.Max(sphereRadius, 0.5),
                        Depth = 0,
                        Density = (float)(0.6 + (1.0 - t) * 0.3),
                        Archetype = CloudArchetype.Column
                    });
                }

                // Center sphere on even floors
                if (floor % 2 == 0)
                {
                    spheres.Add(new CloudSphere
                    {
                        X = (float)wobbleX,
                        Y = (float)y,
                        Z = (float)wobbleZ,
                        Radius = (float)(floorRadius * 0.3),
                        Depth = 0,
                        Density = 0.8f,
                        Archetype = CloudArchetype.Column
                    });
                }
            }

            return spheres;
        }

