        private static List<CloudSphere> GeneratePlatformLayer(CloudLayerConfig layer, ref DeterministicRandom rng)
        {
            var spheres = new List<CloudSphere>();

            int seed = layer.Seed;
            double jitter = layer.Jitter;
            double clustering = layer.Clustering;
            double posVariation = layer.PositionVariation;
            int sizeMin = layer.SizeRange.Min;

            double width = layer.PlatformParams.Width;
            double depth = layer.PlatformParams.Depth;
            double centerThickness = layer.PlatformParams.CenterThickness;
            double edgeThickness = layer.PlatformParams.EdgeThickness;
            int interiorDensity = layer.PlatformParams.InteriorDensity;

            double baseRadius = sizeMin;

            spheres.Add(new CloudSphere
            {
                X = 0, Y = 0, Z = 0,
                Radius = (float)baseRadius,
                Depth = 0, Density = 1.0f,
                Archetype = CloudArchetype.Platform
            });

            (double x, double z)[] interiorPoints = CloudMath.FibonacciSpiral2D(interiorDensity);
            int spiralIdx = 0;

            for (int pi = 0; pi < interiorPoints.Length; pi++)
            {
                (double x, double z) pt = interiorPoints[pi];
                double px = pt.x * width * 0.5;
                double pz = pt.z * depth * 0.5;

                double dist = Math.Sqrt(
                    (px * px) / (width * width * 0.25) + (pz * pz) / (depth * depth * 0.25));
                double thickness = centerThickness * Math.Exp(-dist * dist * 3.0)
                                   + edgeThickness * dist;
                if (thickness < 0.2) continue;

                double yNoise = CloudMath.Perlin3D(px * 0.3, pz * 0.3, seed + 500, seed);
                double y = yNoise * thickness * 0.5
                           + jitter * baseRadius * CloudMath.Perlin3D(px, pz, seed, seed + 1);

                double rNoiseBase = Math.Pow(
                    (CloudMath.Perlin3D(px * 0.5, pz * 0.5, seed + 600 + spiralIdx, seed)
                     + 1.0) * 0.5, 1.8);
                double rNoiseMult = Math.Pow(
                    (CloudMath.Perlin3D(px * 0.5 + 70, pz * 0.5 + 70, seed + 650 + spiralIdx, seed + 1)
                     + 1.0) * 0.5, 1.5);
                double sizeBase = sizeMin + rNoiseBase * (layer.SizeRange.Max - sizeMin);
                double jitterFactor = 1.0 + jitter * (1.0 - clustering);
                double radius = sizeBase * (0.1 + rNoiseMult * 0.9) * jitterFactor;

                double densityVal = (0.3 + 0.7 * (1.0 - dist))
                                    * (clustering > 0.5 ? (0.7 + rNoiseBase * 0.3) : 1.0);

                if (densityVal < 0.1 || radius < 0.3) { spiralIdx++; continue; }

                double platOx = (rng.NextDouble() - 0.5) * 12.0 * radius * posVariation;
                double platOy = (rng.NextDouble() - 0.5) * 12.0 * radius * posVariation;
                double platOz = (rng.NextDouble() - 0.5) * 12.0 * radius * posVariation;

                spheres.Add(new CloudSphere
                {
                    X = (float)(px + platOx),
                    Y = (float)(y + platOy),
                    Z = (float)(pz + platOz),
                    Radius = (float)radius,
                    Depth = 0,
                    Density = (float)densityVal,
                    Archetype = CloudArchetype.Platform
                });
                spiralIdx++;
            }

            return spheres;
        }

