        private struct TreeFrame
        {
            public double X, Y, Z;
            public double DirX, DirY, DirZ;
            public double Radius;
            public int Depth;
            public int PathId;
            public double LengthMult;
        }

        private static List<CloudSphere> GenerateTreeLayer(CloudLayerConfig layer, ref DeterministicRandom rng)
        {
            var spheres = new List<CloudSphere>();
            int globalPathId = 0;

            int seed = layer.Seed;
            double jitter = layer.Jitter;
            double clustering = layer.Clustering;
            double posVariation = layer.PositionVariation;
            int sizeMin = layer.SizeRange.Min;
            int sizeMax = layer.SizeRange.Max;

            double baseRadius = layer.TreeParams.BaseRadius;
            int maxDepth = layer.TreeParams.MaxDepth;
            double branchElongation = layer.TreeParams.BranchElongation;
            double taperRatio = layer.TreeParams.TaperRatio;
            double branchAngle = layer.TreeParams.BranchAngle * Math.PI / 180.0;
            double trunkUpBias = layer.TreeParams.TrunkUpBias;
            double lengthFalloff = layer.TreeParams.LengthFalloff;
            double thicknessFalloff = layer.TreeParams.ThicknessFalloff;

            // Root sphere
            spheres.Add(new CloudSphere
            {
                X = 0, Y = 0, Z = 0,
                Radius = sizeMin,
                Depth = 0, Density = 1.0f,
                Archetype = CloudArchetype.Tree
            });

            var stack = new Stack<TreeFrame>();
            stack.Push(new TreeFrame
            {
                X = 0, Y = 0, Z = 0,
                DirX = 0, DirY = 1, DirZ = 0,
                Radius = sizeMin,
                Depth = 0, PathId = 0, LengthMult = 1.0
            });

            while (stack.Count > 0)
            {
                TreeFrame frame = stack.Pop();
                if (frame.Depth >= maxDepth) continue;
                if (frame.Radius < 0.5) continue;

                double dirLen = Math.Sqrt(
                    frame.DirX * frame.DirX + frame.DirY * frame.DirY + frame.DirZ * frame.DirZ);
                if (dirLen < 1e-15) continue;
                double dirNX = frame.DirX / dirLen;
                double dirNY = frame.DirY / dirLen;
                double dirNZ = frame.DirZ / dirLen;

                double extension = frame.Radius * branchElongation * frame.LengthMult;

                // Perturb direction deterministically
                double a1 = CloudMath.Perlin3D(frame.X * 3, frame.Y * 3, frame.Z * 3, seed + frame.PathId)
                            * branchAngle;
                double a2 = CloudMath.Perlin3D(frame.X * 3, frame.Y * 3, frame.Z * 3 + 50, seed + frame.PathId + 1)
                            * branchAngle;
                double cos1 = Math.Cos(a1), sin1 = Math.Sin(a1);
                double cos2 = Math.Cos(a2), sin2 = Math.Sin(a2);

                double pdx = dirNX * cos1 - dirNY * sin1;
                double pdy = dirNX * sin1 + dirNY * cos1;
                double pdz = dirNZ;
                double pdx2 = pdx * cos2 + pdz * sin2;
                double pdy2 = pdy;
                double pdz2 = -pdx * sin2 + pdz * cos2;
                double pLen = Math.Sqrt(pdx2 * pdx2 + pdy2 * pdy2 + pdz2 * pdz2);
                if (pLen < 1e-15) continue;
                double perturbedDirX = pdx2 / pLen;
                double perturbedDirY = pdy2 / pLen;
                double perturbedDirZ = pdz2 / pLen;

                // Jitter the perturbed direction
                double jitterAngle = jitter * Math.PI
                                     * CloudMath.Perlin3D(frame.X, frame.Y, frame.PathId, seed);
                double jCos = Math.Cos(jitterAngle), jSin = Math.Sin(jitterAngle);
                double jDirX = jCos * perturbedDirX - jSin * perturbedDirY;
                double jDirY = jCos * perturbedDirY + jSin * perturbedDirX;
                double jDirZ = perturbedDirZ;

                // Child position
                double childPosX = frame.X + jDirX * extension
                                   + jitter * baseRadius * CloudMath.Perlin3D(frame.Depth, frame.PathId, seed + 50, seed);
                double childPosY = frame.Y + jDirY * extension
                                   + jitter * baseRadius * CloudMath.Perlin3D(frame.Depth, frame.PathId, seed + 60, seed);
                double childPosZ = frame.Z + jDirZ * extension
                                   + jitter * baseRadius * CloudMath.Perlin3D(frame.Depth, frame.PathId, seed + 70, seed);

                // Child radius
                double sizeNoiseBase = Math.Pow(
                    (CloudMath.Perlin3D(frame.Depth, frame.PathId, seed + 80, seed) + 1.0) * 0.5, 1.8);
                double sizeNoiseMult = Math.Pow(
                    (CloudMath.Perlin3D(frame.Depth, frame.PathId, seed + 82, seed) + 1.0) * 0.5, 1.5);
                double radiusNoise = Math.Pow(
                    (CloudMath.Perlin3D(frame.Depth, frame.PathId, seed + 81, seed) + 1.0) * 0.5, 2.0);
                double szBase = sizeMin + sizeNoiseBase * (sizeMax - sizeMin);
                double childRadius = szBase * taperRatio * thicknessFalloff
                                     * (0.1 + sizeNoiseMult * 0.9)
                                     * (0.3 + radiusNoise * 0.7);
                double childDensity = 1.0 - (frame.Depth / (double)maxDepth) * 0.3;

                // Position jitter
                double treeOx = (rng.NextDouble() - 0.5) * 12.0 * childRadius * posVariation;
                double treeOy = (rng.NextDouble() - 0.5) * 12.0 * childRadius * posVariation;
                double treeOz = (rng.NextDouble() - 0.5) * 12.0 * childRadius * posVariation;

                spheres.Add(new CloudSphere
                {
                    X = (float)(childPosX + treeOx),
                    Y = (float)(childPosY + treeOy),
                    Z = (float)(childPosZ + treeOz),
                    Radius = (float)childRadius,
                    Depth = frame.Depth + 1,
                    Density = (float)childDensity,
                    Archetype = CloudArchetype.Tree
                });

                // Continue main branch
                stack.Push(new TreeFrame
                {
                    X = childPosX, Y = childPosY, Z = childPosZ,
                    DirX = perturbedDirX, DirY = perturbedDirY, DirZ = perturbedDirZ,
                    Radius = childRadius,
                    Depth = frame.Depth + 1,
                    PathId = frame.PathId,
                    LengthMult = frame.LengthMult * lengthFalloff
                });

                // Lateral branches
                double val = (CloudMath.Perlin3D(
                                 frame.X * 2, frame.Y * 2, frame.Z * 2, seed + frame.PathId)
                             + 1.0) * 0.5;
                int lateralCount;
                if (val < 0.4) lateralCount = 0;
                else if (val < 0.75) lateralCount = 1;
                else if (val < 0.95) lateralCount = 2;
                else lateralCount = 3;

                for (int i = 0; i < lateralCount; i++)
                {
                    int lateralPathId = ++globalPathId;
                    double lateralAngle = (i / (double)Math.Max(lateralCount, 1)) * Math.PI * 2
                                          + CloudMath.Perlin3D(frame.PathId * 10, i * 5, seed, seed)
                                            * 0.5 * (1.0 + jitter);

                    double perpX = -dirNZ;
                    double perpZ = dirNX;
                    double latDirX = dirNX * Math.Cos(branchAngle)
                                     + perpX * Math.Sin(lateralAngle) * Math.Sin(branchAngle);
                    double latDirY = dirNY * Math.Cos(branchAngle)
                                     + Math.Sin(branchAngle) * 0.5;
                    double latDirZ = dirNZ * Math.Cos(branchAngle)
                                     + perpZ * Math.Sin(lateralAngle) * Math.Sin(branchAngle);

                    double latLen = Math.Sqrt(latDirX * latDirX + latDirY * latDirY + latDirZ * latDirZ);
                    if (latLen < 1e-15) continue;
                    latDirX /= latLen;
                    latDirY /= latLen;
                    latDirZ /= latLen;

                    double lateralRadius = childRadius * 0.7;
                    if (lateralRadius < 0.5) continue;

                    double lateralPosX = frame.X + latDirX * extension * 0.8;
                    double lateralPosY = frame.Y + latDirY * extension * 0.8;
                    double lateralPosZ = frame.Z + latDirZ * extension * 0.8;

                    double latOx = (rng.NextDouble() - 0.5) * 12.0 * lateralRadius * posVariation;
                    double latOy = (rng.NextDouble() - 0.5) * 12.0 * lateralRadius * posVariation;
                    double latOz = (rng.NextDouble() - 0.5) * 12.0 * lateralRadius * posVariation;

                    spheres.Add(new CloudSphere
                    {
                        X = (float)(lateralPosX + latOx),
                        Y = (float)(lateralPosY + latOy),
                        Z = (float)(lateralPosZ + latOz),
                        Radius = (float)lateralRadius,
                        Depth = frame.Depth + 1,
                        Density = (float)(childDensity * 0.8),
                        Archetype = CloudArchetype.Tree
                    });

                    if (frame.Depth + 1 < maxDepth - 1)
                    {
                        stack.Push(new TreeFrame
                        {
                            X = lateralPosX, Y = lateralPosY, Z = lateralPosZ,
                            DirX = latDirX, DirY = latDirY, DirZ = latDirZ,
                            Radius = lateralRadius,
                            Depth = frame.Depth + 2,
                            PathId = lateralPathId,
                            LengthMult = frame.LengthMult * lengthFalloff * 0.8
                        });
                    }
                }
            }

            return spheres;
        }
    }
}
